import json
from google_adk import Agent

def create_approval_card(report_details: dict) -> str:
    # Define the structured A2UI card with action buttons
    card_layout = {
        "a2ui_version": "2.0.0",
        "components": [
            {
                "type": "card",
                "title": "Expense Approval Required",
                "body": f"Review submission from {report_details['submitter']}: ${report_details['amount']}",
                "status": "warning"
            },
            {
                "type": "button_group",
                "buttons": [
                    {"label": "Approve Request", "action_id": "approve_expense", "variant": "success"},
                    {"label": "Reject Request", "action_id": "reject_expense", "variant": "danger"}
                ]
            }
        ]
    }
    return json.dumps(card_layout)
